import fs from 'node:fs/promises';
import path from 'node:path';

const root = '/tmp/codexdesktop-tasks/electron-webcontentsview-migration';
const evidencePath = path.join(root, 'evidence.jsonl');
const metricsPath = path.join(root, 'metrics.json');
const observedAt = new Date().toISOString();

const queries = [
  'repo:electron/electron WebContentsView BrowserView migration',
  'repo:electron/electron BrowserView deprecated WebContentsView Linux',
  'repo:electron/electron WebContentsView setBounds Linux',
  'repo:electron/electron "setBrowserView" "WebContentsView"',
  '"BrowserView" "WebContentsView" "Linux" Electron',
  '"WebContentsView" "BrowserView" migration Electron'
];

const records = [];
const diagnostics = [];

async function fetchJson(url, headers = {}) {
  const res = await fetch(url, {
    headers: {
      'accept': 'application/vnd.github+json',
      'user-agent': 'codexdesktop-research',
      ...headers
    }
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`${res.status} ${url} ${text.slice(0, 180)}`);
  return JSON.parse(text);
}

async function fetchText(url) {
  const res = await fetch(url, { headers: { 'user-agent': 'codexdesktop-research' } });
  const text = await res.text();
  if (!res.ok) throw new Error(`${res.status} ${url} ${text.slice(0, 180)}`);
  return text;
}

function add(record) {
  records.push({
    observedAt,
    ...record
  });
}

function inferVersion(text) {
  const matches = [...text.matchAll(/Electron(?:\s|\/|:|-)*(v?\d{2,}(?:\.\d+){0,2})/gi)].map(m => m[1]);
  return [...new Set(matches)].slice(0, 4).join(', ') || '';
}

function inferPlatform(text) {
  const low = text.toLowerCase();
  const out = [];
  if (/\blinux|ubuntu|wayland|x11|gtk|gnome|kde|debian|fedora/.test(low)) out.push('Linux');
  if (/\bmacos|darwin|os x/.test(low)) out.push('macOS');
  if (/\bwindows|win32/.test(low)) out.push('Windows');
  return out.join(', ') || '';
}

function concise(text, terms) {
  const lines = text.split(/\n+/).map(s => s.trim()).filter(Boolean);
  const scored = lines.filter(l => terms.some(t => l.toLowerCase().includes(t)));
  return (scored.slice(0, 4).join(' / ') || lines.slice(0, 2).join(' / ')).slice(0, 900);
}

async function official() {
  const docs = [
    ['BrowserView API', 'https://www.electronjs.org/docs/latest/api/browser-view'],
    ['WebContentsView API', 'https://www.electronjs.org/docs/latest/api/web-contents-view'],
    ['BaseWindow API', 'https://www.electronjs.org/docs/latest/api/base-window'],
    ['Electron releases', 'https://releases.electronjs.org/releases/stable']
  ];
  for (const [title, url] of docs) {
    try {
      const text = await fetchText(url);
      add({
        source: 'Electron official docs',
        title,
        url,
        sourceType: 'primary',
        reportedVersion: title === 'Electron releases' ? concise(text, ['43', 'electron']) : 'latest docs',
        targetVersionApplicability: text.includes('43.') || title !== 'Electron releases' ? 'likely' : 'unknown',
        platform: 'cross-platform',
        status: text.includes('Deprecated') || /deprecated/i.test(text) ? 'deprecated/migration guidance present' : 'current official doc',
        claim: concise(text, ['deprecated', 'browserview', 'webcontentsview', 'basewindow', 'webcontents']),
        evidenceStrength: 'high',
        caveat: 'Official docs describe intended API contract, not field behavior.'
      });
    } catch (e) {
      diagnostics.push({ url, error: String(e) });
    }
  }
}

async function githubSearch() {
  const seen = new Set();
  for (const q of queries) {
    try {
      const url = `https://api.github.com/search/issues?q=${encodeURIComponent(q)}&sort=updated&order=desc&per_page=10`;
      const json = await fetchJson(url);
      for (const item of json.items || []) {
        if (seen.has(item.html_url)) continue;
        seen.add(item.html_url);
        const full = await fetchJson(item.url);
        const comments = item.comments_url ? await fetchJson(`${item.comments_url}?per_page=20`).catch(() => []) : [];
        const body = `${full.body || ''}\n${comments.map(c => c.body || '').join('\n')}`;
        const relevant = /BrowserView|WebContentsView|BaseWindow|setBrowserView|contentView|setBounds/i.test(`${item.title}\n${body}`);
        if (!relevant) continue;
        add({
          source: 'GitHub',
          title: item.title,
          url: item.html_url,
          sourceType: /electron\/electron/.test(item.repository_url || '') ? 'firsthand' : 'firsthand',
          reportedVersion: inferVersion(body) || '',
          targetVersionApplicability: /43\./.test(body) ? 'confirmed' : /deprecated|latest|main|current|WebContentsView|BrowserView/i.test(body) ? 'likely' : 'unknown',
          platform: inferPlatform(body),
          status: item.state,
          claim: concise(body, ['browserview', 'webcontentsview', 'basewindow', 'linux', 'setbounds', 'deprecated', 'resize', 'crash', 'focus']),
          evidenceStrength: /steps|repro|reproduction|minimal|expected|actual|electron fiddle|linux|ubuntu/i.test(body) ? 'high' : 'medium',
          caveat: `Updated ${item.updated_at}; GitHub issue text may include multiple participants and versions.`
        });
      }
    } catch (e) {
      diagnostics.push({ query: q, error: String(e) });
    }
  }
}

await fs.writeFile(evidencePath, '');
await official();
await githubSearch();
await fs.writeFile(evidencePath, records.map(r => JSON.stringify(r)).join('\n') + '\n');
const metrics = { ok: true, records: records.length, diagnostics, queries, durationMs: 0 };
await fs.writeFile(metricsPath, JSON.stringify(metrics, null, 2));
console.log(JSON.stringify({ ok: true, records: records.length, gaps: diagnostics.length ? ['some fetch/search diagnostics recorded'] : [], artifacts: { evidence: evidencePath, metrics: metricsPath } }));

